from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize aggregations dictionary
    aggregations = defaultdict(lambda: {
        "count": 0,
        "total_score": 0.0,
        "max_score": float('-inf'),
        "min_score": float('inf')
    })

    # Add custom aggregation functions if provided
    if aggregation_funcs:
        for field, func in aggregation_funcs.items():
            if field not in ["count", "total_score", "max_score", "min_score"]:
                # Initialize custom aggregation fields
                aggregations.default_factory = lambda: {**aggregations.default_factory(), field: []}

    # Iterate through each search result
    for result in search_results:
        # Extract group value from metadata
        group_value = result.metadata.get(group_by_field)

        # Handle missing group values
        if group_value is None or group_value == "":
            group_value = "unknown"

        # Update statistics for this group
        group_data = aggregations[group_value]

        # Default statistics
        group_data["count"] += 1
        group_data["total_score"] += result.score
        if result.score > group_data["max_score"]:
            group_data["max_score"] = result.score
        if result.score < group_data["min_score"]:
            group_data["min_score"] = result.score

        # Custom aggregations
        if aggregation_funcs:
            for field, func in aggregation_funcs.items():
                if field != "count" and field != "total_score" and field != "max_score" and field != "min_score":
                    # Get the field value from result (could be from metadata or top-level)
                    field_value = getattr(result, field, None)
                    if field_value is None:
                        field_value = result.metadata.get(field)

                    # Handle missing values for custom aggregation
                    if field_value is not None:
                        group_data[field].append(field_value)

    # Convert defaultdict to regular dict and calculate final statistics
    final_aggregations = {}
    for group_value, data in aggregations.items():
        # Calculate average score
        avg_score = data["total_score"] / data["count"] if data["count"] > 0 else 0.0

        # Prepare final statistics dictionary
        stats = {
            "count": data["count"],
            "avg_score": round(avg_score, 4),
            "max_score": round(data["max_score"], 4),
            "min_score": round(data["min_score"], 4)
        }

        # Add custom aggregation results
        if aggregation_funcs:
            for field, func in aggregation_funcs.items():
                if field != "count" and field != "total_score" and field != "max_score" and field != "min_score":
                    if data[field]:  # Only calculate if we have values
                        try:
                            stats[field] = func(data[field])
                        except Exception as e:
                            stats[field] = f"Error: {str(e)}"

        final_aggregations[group_value] = stats

    return final_aggregations

